def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                complexity *= 1 + 0.02 * j
            else:
                complexity *= 0.98 - 0.01 * j
            if ratio < 0.1 * j:
                score += (np.sin(j) ** 2 + np.exp(-ratio * j)) * complexity
            else:
                score += (np.sqrt(j*j + 1) + ratio**4) / (j + 1) * complexity
            if (cap * j + j*j) % 9 == 0:
                score *= 1.07
            elif (cap + j*j*j) % 11 == 0:
                score *= 0.93
            if j % 4 == 0:
                for k in range(1, 8):
                    delta = cap - item * (k ** 3)
                    if delta > 0:
                        if delta % (k + 3) == 0:
                            penalty += np.log1p(delta) / (k + 2)
                        else:
                            penalty -= np.sqrt(abs(delta)) / (k + 4)
                    else:
                        penalty -= (abs(delta) ** 1.5) / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.88 - 0.02 * j
            if (cap + j) % 5 == 0:
                penalty += np.cos(j * ratio) * 0.6
            elif (cap * j) % 8 == 3:
                penalty -= np.sin(j + ratio) * 0.4
        score += penalty * 0.9
        score *= adjustment
        if score < 0:
            if cap % 3 == 0:
                priorities[i] = -score * (np.sqrt(cap) + np.log1p(item)) * 1.1
            else:
                priorities[i] = -score * (np.log1p(cap) + np.sqrt(item)) * 0.95
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.power(cap, 0.4) + 1) * (1 + ratio) * 1.05
            elif cap > item * 2:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
            else:
                priorities[i] = -score / (cap + 2) * np.exp(-ratio**2) * 0.9
        if ratio > 1.2:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 2 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if cap % 7 == 0:
            priorities[i] *= 1.08 if ratio < 0.5 else 0.92
    return priorities
